#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <chrono>

template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = memcmp(ref_out, out, n * sizeof(T));
  if (error) {
    for (int64_t i = 0; n > i; i++) {
      if (out[i] != ref_out[i]) {
        printf("@%zu: %lf != %lf\n", i, (double)ref_out[i], (double)out[i]);
        break;
      }
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
__global__ void scanKernelWithConflicts(T* in, T* out, int num_blocks)
{
  int bid = blockIdx.x;
  if (bid >= num_blocks) return;

  T temp[N];
  int thid = threadIdx.x;
  int num_threads = N / 2;

  T *t_in  = in + bid * N;
  T *t_out = out + bid * N;

  if (thid < num_threads) {
    temp[2*thid]   = t_in[2*thid];
    temp[2*thid+1] = t_in[2*thid+1];
  }

  int offset = 1;
  for (int d = N >> 1; 0 < d; d >>= 1)
  {
    if (thid < num_threads) {
      if (d > thid)
      {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        temp[bi] += temp[ai];
      }
      offset = offset * 2;
    }
    if (d > 1) __syncthreads();
  }

  if (thid == 0) temp[N-1] = 0;

  offset = N >> 1;
  for (int d = 1; N > d; d *= 2)
  {
    offset = offset >> 1;
    if (thid < num_threads) {
      if (d > thid)
      {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        T t = temp[ai];
        temp[ai] = temp[bi];
        temp[bi] += t;
      }
    }
    if (d < N/2) __syncthreads();
  }

  if (thid < num_threads) {
    t_out[2*thid] = temp[2*thid];
    t_out[2*thid+1] = temp[2*thid+1];
  }
}

template<typename T, int N>
__global__ void scanKernelNoConflicts(T* in, T* out, int num_blocks)
{
  int bid = blockIdx.x;
  if (bid >= num_blocks) return;

  T temp[2*N]; // Larger temp array to handle padding
  int thid = threadIdx.x;
  int num_threads = N / 2;

  T *t_in  = in + bid * N;
  T *t_out = out + bid * N;

  if (thid < num_threads) {
    int a = thid;
    int b = a + (N/2);
    int oa = OFFSET(a);
    int ob = OFFSET(b);

    temp[a + oa] = t_in[a];
    temp[b + ob] = t_in[b];
  }

  int offset = 1;
  for (int d = N >> 1; 0 < d; d >>= 1)
  {
    if (thid < num_threads) {
      if (d > thid)
      {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        ai = ai + OFFSET(ai);
        bi = bi + OFFSET(bi);
        temp[bi] += temp[ai];
      }
      offset = offset * 2;
    }
    if (d > 1) __syncthreads();
  }

  if (thid == 0) temp[N-1+OFFSET(N-1)] = 0;

  offset = N >> 1;
  for (int d = 1; N > d; d *= 2)
  {
    offset = offset >> 1;
    if (thid < num_threads) {
      if (d > thid)
      {
        int ai = offset*(2*thid+1)-1;
        int bi = offset*(2*thid+2)-1;
        ai = ai + OFFSET(ai);
        bi = bi + OFFSET(bi);
        T t = temp[ai];
        temp[ai] = temp[bi];
        temp[bi] += t;
      }
    }
    if (d < N/2) __syncthreads();
  }

  __syncthreads();

  if (thid < num_threads) {
    int a = thid;
    int b = a + (N/2);
    int oa = OFFSET(a);
    int ob = OFFSET(b);
    t_out[a] = temp[a + oa];
    t_out[b] = temp[b + ob];
  }
}

template<typename T, int N>
void runTest (const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N;
  int64_t bytes = nelems * sizeof(T);

  T *in = (T*) malloc (bytes);
  T *out = (T*) malloc (bytes);
  T *ref_out = (T*) malloc (bytes);

  srand(123);
  for (int64_t idx = 0; nelems > idx; idx++) in[idx] = rand() % 5 + 1;

  // Reference calculation
  T *t_in = in;
  T *t_out = ref_out;
  for (int64_t blk = 0; num_blocks > blk; blk++) {
    t_out[0] = 0;
    for (int i = 1; N > i; i++)
      t_out[i] = t_out[i-1] + t_in[i-1];
    t_out += N;
    t_in += N;
  }

  T *d_in, *d_out;
  cudaMalloc(&d_in, bytes);
  cudaMalloc(&d_out, bytes);
  cudaMemcpy(d_in, in, bytes, cudaMemcpyHostToDevice);

  int threads_per_block = N / 2;
  int grid_dim = (int)num_blocks;
  dim3 block_dim(threads_per_block);

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    scanKernelWithConflicts<T, N><<grid_dim, block_dim>>(d_in, d_out, grid_dim);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }

  cudaMemcpy(d_out, d_in, bytes, cudaMemcpyHostToDevice); // Reset d_out to d_in for next pass if needed, though logic overwrites
  // Actually, the second kernel reads from d_in again, so no need to copy back yet.
  // But we need to copy the result of the first kernel to host for verification if not timing
  cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost);

  if (!timing) verify(ref_out, out, nelems);

  start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scanKernelNoConflicts<T, N><<grid_dim, block_dim>>(d_in, d_out, grid_dim);
  }

  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }

  cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost);
  if (!timing) verify(ref_out, out, nelems);

  cudaFree(d_in);
  cudaFree(d_out);
  free(in);
  free(out);
  free(ref_out);
}

template<int N>
void run (const int n, const int repeat) {
  for (int i = 0; 2 > i; i++) {
    bool report_timing = 0 < i;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<  int, N>(n, repeat, report_timing);
    runTest< long, N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
{
  if (3 != argc) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }
  const int n = atoi(argv[1]);
  const int data_0 = atoi(argv[2]);

  run< 128>(n, data_0);
  run< 256>(n, data_0);
  run< 512>(n, data_0);
  run<1024>(n, data_0);
  run<2048>(n, data_0);

  return 0;
}
